{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream bounded contexts that consume shipment data, and external partner integrations. This is not a minor schema change — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment Management (core domain), with ripple effects into Routing, Notifications, Billing, Tracking, and Partner Integration contexts",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more recipients. After this change, a Shipment is no longer synonymous with a single delivery — it becomes a container for multiple delivery obligations." },
      { "term": "Recipient", "definition": "A party designated to receive goods from a Shipment. Has a name, address, phone number, and now individual delivery preferences. Becomes a first-class entity with its own identity rather than a value object embedded in Shipment." },
      { "term": "Delivery Preference", "definition": "Recipient-level configuration for how and when delivery should occur (e.g., time windows, safe-place instructions, signature requirements). Owned by each Recipient independently." },
      { "term": "Primary Recipient", "definition": "UNDEFINED — the spec does not clarify whether one recipient is primary or authoritative. This is a critical ambiguity." },
      { "term": "Shipment Status", "definition": "Previously a single linear state (e.g., pending → in_transit → delivered). With multiple recipients, status must now be either composite (per-recipient statuses rolled up) or split into per-recipient delivery statuses. The spec is silent on this." },
      { "term": "Delivery Attempt", "definition": "A physical attempt to deliver goods to a specific recipient address. Previously 1:1 with Shipment; now must be scoped to a specific Recipient within a Shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times",
      "invariant": true,
      "invariant_justification": "A Shipment with zero recipients is logically incoherent — there is no delivery obligation without a recipient. This is a structural integrity constraint.",
      "testable_assertion": "shipment.recipients.length >= 1 must hold true at every state transition of the Shipment lifecycle"
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a name, address, and phone number",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to fulfill a physical delivery. Without any one of them, the delivery cannot be attempted or the recipient cannot be contacted.",
      "testable_assertion": "For every recipient R in shipment.recipients: R.name is non-empty AND R.address is a valid deliverable address AND R.phone is a valid phone number"
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment owns their own delivery preferences independently",
      "invariant": true,
      "invariant_justification": "Delivery preferences are physically bound to a recipient's location and availability — they cannot be shared or inherited without corrupting the delivery contract for that recipient.",
      "testable_assertion": "Modifying delivery preferences for Recipient A does not affect delivery preferences for Recipient B within the same Shipment"
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient Shipments must remain valid and functional after migration without data loss or behavioral change",
      "invariant": true,
      "invariant_justification": "2 million production shipments represent live business state. Any migration that alters their semantics or loses data corrupts the system of record.",
      "testable_assertion": "For every pre-migration shipment S: S has exactly one recipient after migration, and S.recipient[0].name == old S.recipient.name AND S.recipient[0].address == old S.recipient.address AND S.recipient[0].phone == old S.recipient.phone"
    },
    {
      "id": "BR-5",
      "rule": "Recipient addresses within a single Shipment SHOULD be deduplicated or validated to prevent duplicate deliveries to the same physical address",
      "invariant": false,
      "invariant_justification": "This is a business policy to prevent waste and confusion, but there are legitimate cases where two different recipients share an address (e.g., different apartment units, different people at same business).",
      "testable_assertion": "System warns when two recipients in the same shipment have addresses that normalize to the same geocoordinates within a configurable threshold"
    },
    {
      "id": "BR-6",
      "rule": "A Shipment's overall status must be derivable from the individual delivery statuses of its recipients",
      "invariant": true,
      "invariant_justification": "If Shipment status and Recipient delivery statuses can diverge with no derivation rule, the system enters an inconsistent state where the Shipment claims 'delivered' but a recipient has not received goods.",
      "testable_assertion": "shipment.status == f(shipment.recipients[*].deliveryStatus) for a well-defined function f (e.g., Shipment is 'delivered' only when ALL recipients are 'delivered'; 'partially_delivered' when at least one but not all are 'delivered')"
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format until partners explicitly migrate to the new format",
      "invariant": true,
      "invariant_justification": "Breaking partner API contracts causes immediate business disruption — failed integrations, lost orders, SLA violations. This is a contractual obligation, not a preference.",
      "testable_assertion": "Partner API responses for multi-recipient shipments serialize to the legacy single-recipient format with a deterministic selection rule (e.g., first recipient, primary recipient) OR return an error if no unambiguous mapping exists"
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies multiple recipients with distinct addresses and delivery preferences",
      "then": "The Shipment is created with all recipients preserved, each with their own name, address, phone, and delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment from before the migration",
      "when": "It is retrieved via any API or UI",
      "then": "It appears with exactly one recipient, with all original data intact, and behaves identically to pre-migration behavior"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "The Shipment status is queried",
      "then": "The Shipment status reflects a partial delivery state (e.g., 'partially_delivered') and individual recipient statuses are independently queryable"
    },
    {
      "id": "AC-4",
      "given": "An external partner requests shipment data via the existing API",
      "when": "The shipment has multiple recipients",
      "then": "The API responds in the legacy format using a deterministic mapping rule without breaking the partner's integration"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with two recipients",
      "when": "One recipient's delivery preference is updated",
      "then": "Only that recipient's preferences change; the other recipient's preferences are unaffected"
    },
    {
      "id": "AC-6",
      "given": "A user attempts to create a Shipment with zero recipients",
      "when": "The creation request is submitted",
      "then": "The system rejects the request with a validation error; no Shipment is persisted"
    },
    {
      "id": "AC-7",
      "given": "A user attempts to remove the last remaining recipient from an existing Shipment",
      "when": "The removal request is submitted",
      "then": "The system rejects the request, preserving the Shipment with its current recipient"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient Shipment where all recipients share the same physical address",
      "expected_behavior": "System allows it but surfaces a warning. Legitimate use case: different people at same office. Each recipient retains independent delivery status and preferences."
    },
    {
      "scenario": "A partner API receives a multi-recipient shipment but only supports single-recipient format",
      "expected_behavior": "The integration layer applies the deterministic mapping rule (e.g., primary recipient). If no primary is designated and multiple exist, the system must either fail loudly or use the first recipient — NOT silently drop recipients."
    },
    {
      "scenario": "Delivery fails for one recipient but succeeds for another — customer requests full shipment cancellation",
      "expected_behavior": "Cancellation policy must account for partial fulfillment. Cannot simply 'cancel shipment' when physical goods have already been delivered to one recipient. Requires per-recipient cancellation or return flow."
    },
    {
      "scenario": "In-flight shipments during migration (status: in_transit with single recipient)",
      "expected_behavior": "Migration must not disrupt active delivery workflows. In-flight shipments are migrated to the new schema but remain single-recipient. No mid-delivery schema changes that could confuse drivers or tracking systems."
    },
    {
      "scenario": "Maximum number of recipients per shipment",
      "expected_behavior": "The spec says 'one or more' with no upper bound. Without a practical limit, this could be abused or cause performance issues. A configurable maximum (policy, not invariant) should be enforced."
    },
    {
      "scenario": "Recipient ordering — does the order of recipients in a multi-recipient shipment imply delivery sequence?",
      "expected_behavior": "AMBIGUOUS. If order implies routing sequence, this has major implications for route optimization. If unordered, the system needs a separate mechanism for delivery sequencing. The spec is silent."
    },
    {
      "scenario": "Billing attribution — who pays for a multi-recipient shipment?",
      "expected_behavior": "AMBIGUOUS. Is it one charge for the shipment? Per-recipient charges? The billing model fundamentally changes if a 'shipment' now represents multiple physical deliveries to different locations."
    },
    {
      "scenario": "Notifications — a delivery event occurs for one recipient",
      "expected_behavior": "Only the affected recipient should be notified, not all recipients on the shipment. Notification context must include which recipient the event pertains to."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments may fundamentally change the pricing model. A single shipment to 5 addresses is operationally 5 deliveries — if priced as one shipment, margin erosion is severe. Conversely, if priced per-recipient, it becomes a new revenue lever. The billing bounded context must be redesigned. Migration of 2M records also carries direct engineering cost.",
    "operational": "HIGH. Route optimization algorithms must change from 'one shipment = one stop' to 'one shipment = N stops'. Driver apps, warehouse picking, and dispatch systems all assume 1:1. Partial delivery states introduce new exception-handling workflows. Support team needs retraining for multi-recipient scenarios.",
    "user": "MEDIUM-HIGH. Senders gain flexibility (one shipment, multiple recipients — gift scenarios, business distribution). But recipients may be confused by shared tracking numbers. UX for tracking must show per-recipient status. The 'delivered' notification must be recipient-scoped, not shipment-scoped.",
    "risk": "HIGH. Partner API backward compatibility is the highest-risk item — any regression breaks live integrations. Data migration of 2M records is high-risk for an active production system. The ambiguities around billing, recipient ordering, and primary recipient designation could lead to incorrect implementations if not resolved before development begins.",
    "stakeholders_affected": [
      { "group": "Senders (customers)", "impact": "New capability to send to multiple recipients in one shipment. Must understand new pricing model and tracking behavior." },
      { "group": "Recipients", "impact": "May share a tracking number with strangers. Privacy concern if recipient list is visible. Delivery preferences now critical since each recipient may have different needs." },
      { "group": "Drivers/Couriers", "impact": "A single shipment now means multiple stops. Driver app UI, route planning, and completion workflows must support per-recipient delivery confirmation." },
      { "group": "External Partners", "impact": "API contract changes. Partners on legacy format need backward-compatible responses. Partners who want multi-recipient support need a new API version." },
      { "group": "Support Team", "impact": "Increased complexity in handling disputes, refunds, and delivery issues. A shipment partially delivered to 3 of 5 recipients requires new resolution workflows." },
      { "group": "Finance/Billing", "impact": "Pricing model must be redefined. Revenue recognition per shipment changes if one shipment maps to multiple delivery events." },
      { "group": "Warehouse/Fulfillment", "impact": "Picking and packing may need to produce multiple packages per shipment, or a single package with multiple delivery labels." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is dangerously underspecified for a change of this magnitude. The core model change (1:N recipients) is clear, but at least 4 critical domain questions are unanswered: (1) Is there a primary recipient concept? (2) How does billing work? (3) Does recipient order imply delivery sequence? (4) What is the legacy API mapping rule for multi-recipient shipments? Without answers, any implementation risks encoding incorrect assumptions as business rules. Additionally, the interaction between multi-recipient shipments and shipment status is unspecified — this is a fundamental domain concept that cannot be guessed.",
    "high_confidence_areas": [
      "At least one recipient is required (invariant)",
      "Each recipient owns independent delivery preferences",
      "Backward compatibility for 2M existing single-recipient shipments is non-negotiable",
      "Partner API backward compatibility is required"
    ],
    "low_confidence_areas": [
      "Primary recipient designation — does one exist? Is it required?",
      "Billing model for multi-recipient shipments",
      "Recipient ordering semantics (ordered delivery sequence vs. unordered set)",
      "Legacy API mapping rule when multiple recipients exist",
      "Shipment-level status derivation from per-recipient statuses",
      "Whether a multi-recipient shipment is one physical package or multiple packages",
      "Privacy implications — can Recipient A see Recipient B's info?"
    ],
    "assumptions": [
      "Delivery preferences are limited to logistics concerns (time windows, safe-place, signature) — not payment or billing preferences",
      "The migration is an online migration — the system cannot go offline to migrate 2M records",
      "Recipient is being promoted from a value object to an entity with its own identity",
      "External partners are on contractual SLAs that prevent unilateral API changes"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define a 'primary recipient' concept. Many downstream systems (billing address, partner API serialization, tracking page default view) need a single authoritative recipient. Without this, implementations will make inconsistent ad-hoc choices.",
      "affected_stakeholders": ["External Partners", "Billing/Finance", "Support Team"],
      "options": [
        "A: Require one recipient to be designated as 'primary' — simplifies backward compatibility but adds UX complexity",
        "B: All recipients are equal — simpler model but forces every consumer to handle N recipients",
        "C: First recipient is implicitly primary — convention-based, fragile, but zero UX cost"
      ],
      "recommendation": "Option A. An explicit primary recipient provides a clean backward-compatible mapping for partner APIs and billing, without relying on fragile ordering conventions."
    },
    {
      "type": "ambiguity",
      "description": "Billing model for multi-recipient shipments is completely unspecified. Is a 3-recipient shipment billed as 1 shipment or 3 deliveries? This has direct revenue and margin impact.",
      "affected_stakeholders": ["Finance/Billing", "Senders", "Product Team"],
      "options": [
        "A: Bill per shipment (flat) — simpler, but potential margin loss on multi-stop shipments",
        "B: Bill per recipient (base + per-stop) — fair cost attribution but pricing complexity increases",
        "C: Tiered pricing — base shipment fee plus incremental per-recipient fee"
      ],
      "recommendation": "Option C. Tiered pricing reflects the actual cost structure (fixed logistics overhead + variable per-stop cost) and prevents margin erosion while remaining competitive."
    },
    {
      "type": "ambiguity",
      "description": "Does recipient ordering within a shipment imply delivery sequence? This affects route optimization, driver experience, and whether recipients can be reordered after creation.",
      "affected_stakeholders": ["Drivers/Couriers", "Route Optimization", "Senders"],
      "options": [
        "A: Ordered — recipient position implies delivery sequence, immutable after dispatch",
        "B: Unordered — route optimization determines delivery sequence independently",
        "C: Sender-suggested order — hints for optimization but not binding"
      ],
      "recommendation": "Option B. Let the routing context own delivery sequencing. The Shipment context should treat recipients as an unordered set. Coupling ordering to the recipient list conflates two concerns."
    },
    {
      "type": "ambiguity",
      "description": "Shipment-level status derivation is undefined. With N recipients each having their own delivery status, what does the Shipment's status mean? This affects every consumer of shipment status — tracking pages, partner APIs, dashboards, SLA calculations.",
      "affected_stakeholders": ["All stakeholders"],
      "options": [
        "A: Shipment status is the 'worst' recipient status (any failed = shipment failed)",
        "B: Introduce 'partially_delivered' and derive from recipient statuses compositionally",
        "C: Remove shipment-level status entirely — only expose per-recipient statuses"
      ],
      "recommendation": "Option B. A composite status with 'partially_delivered' preserves backward compatibility for single-recipient shipments (where it degenerates to the current model) while accurately representing multi-recipient reality."
    },
    {
      "type": "missing_context",
      "description": "Is a multi-recipient shipment physically one package making multiple stops, or multiple packages from the same origin? This fundamentally changes warehouse operations, labeling, and what 'shipment' means in the physical world.",
      "affected_stakeholders": ["Warehouse/Fulfillment", "Drivers/Couriers", "Product Team"],
      "options": [
        "A: One package, multiple stops (like a bus route)",
        "B: Multiple packages, one logical shipment (like a batch order)",
        "C: Either — configurable per shipment"
      ],
      "recommendation": "Escalate to product team. This is a physical logistics question that determines the entire fulfillment model. Cannot proceed without clarity."
    }
  ],

  "rejection_reasons": []
}

